local function _pwurstaqakmm(encoded, keys)
    local lines = {}
    local current = ""
    for i = 1, #encoded do
        local ch = encoded:sub(i, i)
        if ch == "|" then
            if #current > 0 then table.insert(lines, current) end
            current = ""
        else
            current = current .. ch
        end
    end
    if #current > 0 then table.insert(lines, current) end

    local b = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
    local result = {}
    for idx, line in ipairs(lines) do
        local key = keys[idx] or 0
        local cleaned = line:gsub("[^" .. b .. "=]", "")
        local decoded = {}
        for j = 1, #cleaned, 4 do
            local a = (b:find(cleaned:sub(j,j)) or 1) - 1
            local c = (b:find(cleaned:sub(j+1,j+1)) or 1) - 1
            local d = (b:find(cleaned:sub(j+2,j+2)) or 1) - 1
            local e = (b:find(cleaned:sub(j+3,j+3)) or 1) - 1
            local n = a * 262144 + c * 4096 + d * 64 + e
            table.insert(decoded, string.char(math.floor(n / 65536) % 256))
            if cleaned:sub(j+2,j+2) ~= "=" then
                table.insert(decoded, string.char(math.floor(n / 256) % 256))
            end
            if cleaned:sub(j+3,j+3) ~= "=" then
                table.insert(decoded, string.char(n % 256))
            end
        end
        local xored = {}
        for k = 1, #decoded do
            xored[k] = string.char(string.byte(decoded[k]) ~ key)
        end
        table.insert(result, table.concat(xored))
    end
    return table.concat(result, "\n")
end

